+
+#[test]
+fn errno_linux_specific_codes() {
+    let p = unsafe { __errno_location() };
+    let original = unsafe { *p };
+
+    let codes: &[c_int] = &[
+        libc::ENOMEDIUM,
+        libc::EMEDIUMTYPE,
+        libc::ECANCELED,
+        libc::ENOKEY,
+        libc::EKEYEXPIRED,
+        libc::EKEYREVOKED,
+        libc::EKEYREJECTED,
+        libc::EOWNERDEAD,
+        libc::ENOTRECOVERABLE,
+    ];
+
+    for &code in codes {
+        unsafe { *p = code };
+        assert_eq!(unsafe { *p }, code, "errno should hold Linux code {code}");
+    }
+
+    unsafe { *p = original };
+}
